INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 6, 0, 129911, 0, 1, 0, 0.8, 6011, 11);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 6, "", 0, "", "", "", "", 6012, 91);
