INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0, "vo_minigame_1013_top_talk_6_002", 6, "", "vo_minigame_1013", "", 0, "", "", 6015, 21);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (9, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 6, 0, 129811, 0, 1, 0, 0.3, 6016, 11);
